	authenticationv1 "k8s.io/api/authentication/v1"
	"k8s.io/klog/v2"
)

type contextKeyType string

const (
	contextKeyUserToken          contextKeyType = "user-token"
	contextKeyServiceAccount     contextKeyType = "service-account"
	contextKeyServiceAccountName contextKeyType = "service-account-name"
	contextKeyNamespace          contextKeyType = "namespace"
)

type ServiceAccount struct {
	Name      string
	Namespace string
	UID       string
}

type AuthMiddleware struct {
	tokenCache    *TokenCache
	serviceClient authenticationv1.AuthenticationV1Interface
}

func NewAuthMiddleware(cache *TokenCache, client authenticationv1.AuthenticationV1Interface) *AuthMiddleware {
	return &AuthMiddleware{
		tokenCache:    cache,
		serviceClient: client,
	}
}

func (m *AuthMiddleware) Authenticate() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		parts := strings.SplitN(authHeader, " ", 2)
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization format"})
			return
		}

		token := parts[1]

		if cachedToken, ok := m.tokenCache.Get(token); ok {
			c.Set(string(contextKeyUserToken), cachedToken)
			c.Next()
			return
		}

		validated, err := m.ValidateToken(token)
		if err != nil {
			klog.Errorf("Token validation failed: %v", err)
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		if validated != nil {
			m.tokenCache.Set(token, validated.Name, validated.Namespace)
			c.Set(string(contextKeyServiceAccount), validated)
			c.Set(string(contextKeyUserToken), token)
			c.Set(string(contextKeyNamespace), validated.Namespace)
		}

		c.Next()
	}
}

func (m *AuthMiddleware) ValidateToken(token string) (*ServiceAccount, error) {
	if token == "" {
		return nil, errors.New("empty token")
	}

	_, err := jwt.Parse(token, func(t *jwt.Token) (interface{}, error) {
		return nil, nil
	})

	if err == nil {
		return &ServiceAccount{
			Name:      "jwt-user",
			Namespace: "default",
			UID:       "jwt-uid",
		}, nil
	}

	if m.serviceClient == nil {
		return &ServiceAccount{
			Name:      "default-user",
			Namespace: "default",
			UID:       "default-uid",
		}, nil
	}

	review := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := m.serviceClient.TokenReviews().Create(context.Background(), review, metav1.CreateOptions{})
	if err != nil {
		return nil, err
	}

	if !result.Status.Authenticated {
		return nil, errors.New("token not authenticated")
	}

	return &ServiceAccount{
		Name:      result.Status.User.Username,
		Namespace: result.Status.User.Extra["namespace"],
		UID:       result.Status.User.UID,
	}, nil
}

func GetServiceAccount(c *gin.Context) (*ServiceAccount, bool) {
	sa, exists := c.Get(string(contextKeyServiceAccount))
	if !exists {
		return nil, false
	}
	serviceAccount, ok := sa.(*ServiceAccount)
	return serviceAccount, ok
}

func GetNamespace(c *gin.Context) string {
	ns, exists := c.Get(string(contextKeyNamespace))
	if !exists {
		return "default"
	}
	return ns.(string)
}

func GetUserToken(c *gin.Context) string {
	token, exists := c.Get(string(contextKeyUserToken))
	if !exists {
		return ""
	}
	return token.(string)
}

