	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client"
)

const (
	restConfigQPS   = 50
	restConfigBurst = 100
)

type ClientCache struct {
	mu      sync.RWMutex
	clients map[string]*K8sClient
}

func NewClientCache() *ClientCache {
	return &ClientCache{
		clients: make(map[string]*K8sClient),
	}
}

type K8sClient struct {
	Clientset       *kubernetes.Clientset
	DynamicClient   dynamic.Interface
	Scheme          *runtime.Scheme
	BaseConfig      *rest.Config
	ClientCache     *ClientCache
	DynamicInformer informers
	InformerFactory interface{}
	PodInformer     interface{}
	PodLister       interface{}
}

func GetOrCreateUserK8sClient(ctx context.Context, cache *ClientCache, namespace string, baseConfig *rest.Config) (*K8sClient, error) {
	cache.mu.RLock()
	if cli, ok := cache.clients[namespace]; ok {
		cache.mu.RUnlock()
		return cli, nil
	}
	cache.mu.RUnlock()

	cache.mu.Lock()
	defer cache.mu.Unlock()

	if cli, ok := cache.clients[namespace]; ok {
		return cli, nil
	}

	config := *baseConfig
	config.QPS = restConfigQPS
	config.Burst = restConfigBurst

	clientset, err := kubernetes.NewForConfig(&config)
	if err != nil {
		return nil, err
	}

	dynamicClient, err := dynamic.NewForConfig(&config)
	if err != nil {
		return nil, err
	}

	scheme := runtime.NewScheme()
	if err := corev1.AddToScheme(scheme); err != nil {
		return nil, err
	}

	cli := &K8sClient{
		Clientset:     clientset,
		DynamicClient: dynamicClient,
		Scheme:        scheme,
		BaseConfig:    &config,
		ClientCache:   cache,
	}

	cache.clients[namespace] = cli
	klog.Infof("Created new K8s client for namespace: %s", namespace)

	return cli, nil
}

