)

type SandboxReconciler struct {
	Client   client.Client
	Scheme   *runtime.Scheme
	watchers map[string]chan struct{}
	mu       sync.RWMutex
}

type SandboxStatusUpdate struct {
	Name      string
	Namespace string
	Phase     string
	Message   string
	Ready     bool
}

func NewSandboxReconciler(c client.Client, scheme *runtime.Scheme) *SandboxReconciler {
	return &SandboxReconciler{
		Client:   c,
		Scheme:   scheme,
		watchers: make(map[string]chan struct{}),
	}
}

func (r *SandboxReconciler) WatchSandboxOnce(ctx context.Context, name, namespace string, timeout time.Duration) (*SandboxStatusUpdate, error) {
	watchKey := namespace + "/" + name

	r.mu.RLock()
	if _, exists := r.watchers[watchKey]; exists {
		r.mu.RUnlock()
		return nil, errors.New("already watching this sandbox")
	}
	r.mu.RUnlock()

	stopCh := make(chan struct{})
	r.mu.Lock()
	r.watchers[watchKey] = stopCh
	r.mu.Unlock()

	defer func() {
		r.mu.Lock()
		delete(r.watchers, watchKey)
		r.mu.Unlock()
		close(stopCh)
	}()

	done := make(chan *SandboxStatusUpdate, 1)
	go func() {
		status, err := r.getSandboxStatus(ctx, name, namespace, stopCh)
		if err != nil {
			klog.Errorf("Failed to get sandbox status: %v", err)
			done <- nil
			return
		}
		done <- status
	}()

	select {
	case status := <-done:
		if status == nil {
			return nil, errors.New("failed to get sandbox status")
		}
		return status, nil
	case <-time.After(timeout):
		return nil, errors.New("timeout waiting for sandbox status")
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

func (r *SandboxReconciler) getSandboxStatus(ctx context.Context, name, namespace string, stopCh <-chan struct{}) (*SandboxStatusUpdate, error) {
	ticker := time.NewTicker(1 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-stopCh:
			return nil, errors.New("watch stopped")
		case <-ctx.Done():
			return nil, ctx.Err()
		case <-ticker.C:
			obj := &unstructured.Unstructured{}
			obj.SetGroupVersionKind(schema.GroupVersionKind{
				Group:   "agentcube.io",
				Version: "v1",
				Kind:    "Sandbox",
			})

			if err := r.Client.Get(ctx, client.ObjectKey{Name: name, Namespace: namespace}, obj); err != nil {
				klog.V(4).Infof("Polling sandbox %s/%s: %v", namespace, name, err)
				continue
			}

			phase, found, _ := unstructured.NestedString(obj.Object, "status", "phase")
			if !found {
				phase = "Pending"
			}

			message, _, _ := unstructured.NestedString(obj.Object, "status", "message")
			ready, _, _ := unstructured.NestedBool(obj.Object, "status", "ready")

			return &SandboxStatusUpdate{
				Name:      name,
				Namespace: namespace,
				Phase:     phase,
				Message:   message,
				Ready:     ready,
			}, nil
		}
	}
}

func (r *SandboxReconciler) WaitForSandboxReady(ctx context.Context, name, namespace string, timeout time.Duration) error {
	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		default:
		}

		status, err := r.getSandboxStatus(ctx, name, namespace, nil)
		if err != nil {
			time.Sleep(500 * time.Millisecond)
			continue
		}

		if status.Phase == "Ready" || status.Ready {
			return nil
		}

		if status.Phase == "Failed" {
			return errors.New("sandbox failed: " + status.Message)
		}

		time.Sleep(500 * time.Millisecond)
	}
}

func MarshalStatusUpdate(u *SandboxStatusUpdate) ([]byte, error) {
	return json.Marshal(u)
}

func UnmarshalStatusUpdate(data []byte) (*SandboxStatusUpdate, error) {
	var status SandboxStatusUpdate
	if err := json.Unmarshal(data, &status); err != nil {
		return nil, err
	}
	return &status, nil
}

