	}
}

func TestNewSessionNotFoundError(t *testing.T) {
	err := NewSessionNotFoundError("session-123")
	if err == nil {
		t.Fatal("expected error, got nil")
	}

	sfe, ok := err.(*sessionNotFoundError)
	if !ok {
		t.Fatalf("expected *sessionNotFoundError, got %T", err)
	}

	if sfe.sessionID != "session-123" {
