See the License for the specific language governing permissions and
limitations under the License.
*/

package store

import (
	"context"
	"encoding/json"
	"errors"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type valkeyStore struct {
	cli                  valkey.Client
	sessionPrefix        string
	expiryIndexKey       string
	lastActivityIndexKey string
}

func makeValkeyOptions() valkey.ClientOption {
	addr := os.Getenv("VALKEY_ADDR")
	if addr == "" {
		addr = "localhost:6379"
	}
	password := os.Getenv("VALKEY_PASSWORD")

	opts := valkey.ClientOption{
		InitAddress: []string{addr},
		Password:    password,
	}

	if strings.ToLower(os.Getenv("VALKEY_DISABLE_CACHE")) == "true" {
		opts.DisableCache = true
	}
	if strings.ToLower(os.Getenv("VALKEY_FORCE_SINGLE")) == "true" {
		opts.ForceSingleClient = true
	}

	return opts
}

func newValkeyClient(opts valkey.ClientOption) (*valkeyStore, error) {
	cli, err := valkey.NewClient(opts)
	if err != nil {
		return nil, err
	}
	return &valkeyStore{
		cli:                  cli,
		sessionPrefix:        "session:",
		expiryIndexKey:       "session:expiry",
		lastActivityIndexKey: "session:last_activity",
	}, nil
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	result := v.cli.B().Ping().Build()
	resp := v.cli.Do(ctx, result)
	if resp.Error() != nil {
		return resp.Error()
	}
	if resp.String() != "PONG" {
		return errors.New("unexpected PING response")
	}
	return nil
}

func (v *valkeyStore) sessionKey(sessionID string) string {
	return v.sessionPrefix + sessionID
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := v.sessionKey(sessionID)
	result := v.cli.B().Get().Key(key).Build()
	resp := v.cli.Do(ctx, result)
	if resp.Error() != nil {
		if errors.Is(resp.Error(), valkey.Nil) {
			return nil, ErrNotFound
		}
		return nil, resp.Error()
	}

	data, err := resp.String()
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}
	return &sandbox, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt is zero")
	}

	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	key := v.sessionKey(sandboxStore.SessionID)
	cmds := []valkey.Commands{
		v.cli.B().Setnx().Key(key).Value(string(data)).Build(),
		v.cli.B().Zadd().Key(v.expiryIndexKey).ScoreMember(v.cli.B().Zadd().ScoreMember().Score(float64(sandboxStore.ExpiresAt.Unix())).Member(sandboxStore.SessionID).Build()).Build(),
		v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember(v.cli.B().Zadd().ScoreMember().Score(float64(time.Now().Unix())).Member(sandboxStore.SessionID).Build()).Build(),
	}

	for _, cmd := range cmds {
		if err := v.cli.Do(ctx, cmd).Error(); err != nil {
			return err
		}
	}
	return nil
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}

	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return err
	}

	key := v.sessionKey(sandboxStore.SessionID)
	result := v.cli.B().Set().Key(key).Value(string(data)).Xx().Build()
	resp := v.cli.Do(ctx, result)
	if resp.Error() != nil {
		return ErrNotFound
	}
	return nil
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := v.sessionKey(sessionID)
	cmds := []valkey.Commands{
		v.cli.B().Del().Key(key).Build(),
		v.cli.B().Zrem().Key(v.expiryIndexKey).Members(sessionID).Build(),
		v.cli.B().Zrem().Key(v.lastActivityIndexKey).Members(sessionID).Build(),
	}

	for _, cmd := range cmds {
		if err := v.cli.Do(ctx, cmd).Error(); err != nil {
			return err
		}
	}
	return nil
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	result := v.cli.B().Zrangebyscore().Key(v.expiryIndexKey).Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, limit).Build()
	resp := v.cli.Do(ctx, result)
	members, err := resp.StringSlice()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, members)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	result := v.cli.B().Zrangebyscore().Key(v.lastActivityIndexKey).Min("-inf").Max(strconv.FormatInt(before.Unix(), 10)).Limit(0, limit).Build()
	resp := v.cli.Do(ctx, result)
	members, err := resp.StringSlice()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, members)
}

func (v *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = v.sessionKey(id)
	}

	cmds := make([]valkey.Commands, len(keys))
	for i, key := range keys {
		cmds[i] = v.cli.B().Get().Key(key).Build()
	}

	result := v.cli.DoMulti(ctx, cmds...)
	var resultList []*types.SandboxInfo
	for _, resp := range result {
		data, err := resp.String()
		if err != nil {
			continue
		}
		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			continue
		}
		resultList = append(resultList, &sandbox)
	}
	return resultList, nil
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("session ID is empty")
	}

	key := v.sessionKey(sessionID)
	exists := v.cli.B().Exists().Key(key).Build()
	resp := v.cli.Do(ctx, exists)
	count, _ := resp.Int()
	if count == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	zaddCmd := v.cli.B().Zadd().Key(v.lastActivityIndexKey).ScoreMember(
		v.cli.B().Zadd().ScoreMember().Score(float64(at.Unix())).Member(sessionID).Build(),
	).Build()
	return v.cli.Do(ctx, zaddCmd).Error()
}

func (v *valkeyStore) Close() error {
	v.cli.Close()
	return nil
}

